class Solution:
    def setZeroes(self, matrix):
        rows = {r for r, row in enumerate(matrix) for c, value in enumerate(row) if value == 0}
        cols = {c for r, row in enumerate(matrix) for c, value in enumerate(row) if value == 0}
        for r in range(len(matrix)):
            for c in range(len(matrix[0])):
                if r in rows or c in cols: matrix[r][c] = 0
